+        let sk = X25519SecretKey::from_bytes(bytes);
+        // Due to X25519 clamping, to_bytes may differ from input.
+        // But from_bytes(to_bytes()) should produce same public key.
+        let sk2 = X25519SecretKey::from_bytes(sk.to_bytes());
